import{_ as e,c as a,o as r,ag as l}from"./chunks/framework.DPDPlp3K.js";const m=JSON.parse('{"title":"一元机场 Clash For OpenWrt使用教程","description":"一元机场客户端下载","frontmatter":{"title":"一元机场 Clash For OpenWrt使用教程","description":"一元机场客户端下载","head":[["meta",{"name":"keywords","content":"一元机场,机场推荐,VPN,科学上网,网络加速器"}],["link",{"rel":"canonical","href":"https://www.yiyuanvpn.org/wiki/openWrt.html"}],["meta",{"property":"og:local","content":"en-US"}],["meta",{"property":"og:title","content":"一元机场"}],["meta",{"property":"og:description","content":"一元机场，一元机场官网，一元机场梯子，一元机场登录地址"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://www.yiyuanvpn.org/wiki/openWrt.html"}],["meta",{"property":"og:image","content":"https://www.yiyuanvpn.org/android-chrome-192x192.png"}],["meta",{"property":"og:image:width","content":"192"}],["meta",{"property":"og:image:height","content":"192"}],["meta",{"property":"og:image:type","content":"image/png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"author","content":"一元机场"}],["meta",{"name":"twitter:label1","content":"作者"}],["meta",{"name":"twitter:data1","content":"一元机场"}]]},"headers":[],"relativePath":"wiki/openWrt.md","filePath":"wiki/openWrt.md"}'),o={name:"wiki/openWrt.md"};function i(n,t,p,s,h,c){return r(),a("div",null,t[0]||(t[0]=[l('<h1 id="clash-小猫咪-for-openwrt" tabindex="-1">Clash(小猫咪) For OpenWrt <a class="header-anchor" href="#clash-小猫咪-for-openwrt" aria-label="Permalink to &quot;Clash(小猫咪) For OpenWrt&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>Clash 是基于 Go语言 开发的一款代理工具，支持 Linux/MacOS/Windows/Android 等多平台，支持 SS/V2Ray（不支持SSR）节点，带有强大且支持高度自定义的规则分流功能（类似于Surge的配置）。</p><div class="tip custom-block"><p class="custom-block-title">📝 注意</p><p>由于客户端依然受到长期更新支持，开发过程中可能出现界面或相关功能与教程不符。本教程仅供参考，具体操作需要根据实际情况调整。</p></div><p>温馨提示(1)：<a href="/">一元机场</a>采用较新的订阅配置文件，旧版OpenClash内核无法正常识别，教程演示将采用普适性的兼容配置方案，您可以根据需要自行调整。</p><p>温馨提示(2)：如需使用默认的订阅配置文件，请自行理解并手动开启Meta内核或使用TUN网卡模式，该教程将无任何参考意义，请不要跟从本教程的步骤执行。</p><h2 id="一、下载客户端" tabindex="-1">一、下载客户端 <a class="header-anchor" href="#一、下载客户端" aria-label="Permalink to &quot;一、下载客户端&quot;">​</a></h2><p>OpenClash下载地址：</p><p><a href="https://github.com/vernesong/OpenClash/releases" target="_blank" rel="noreferrer">立即下载(作者页面)</a></p><ol><li>下载并安装上方提供的 ”OpenClash” 客户端到您的 ”OpenWrt路由器” 。</li><li>客户端安装过程结束后在左侧边栏的 ”服务” 分类，找到并选择刚刚安装好的 ”OpenClash” 客户端程序。</li></ol><h2 id="二、设置订阅地址" tabindex="-1">二、设置订阅地址 <a class="header-anchor" href="#二、设置订阅地址" aria-label="Permalink to &quot;二、设置订阅地址&quot;">​</a></h2><ol><li>在 ”一元机场” 官网，通过网页端进入 ”主页” -&gt; ”我的订阅” 一栏，点击 ”一键订阅” 按钮即可选择 ”复制订阅地址” 。</li><li>回到 ”OpenClash” 设置页，在 ”配置订阅” 的分页底部点击 ”添加” 按钮。</li><li>在添加过程中， ”配置文件名” 部分填写 ”一元机场” 。</li><li>”订阅地址” 则粘贴刚刚从网页端复制下来的订阅地址。</li><li>”User-Agent” 选择 ”clash.meta” 。</li><li>勾选 ”在线订阅转换” ，在下拉栏中选择任意一个可用的订阅转换服务(也可以保持默认)。</li><li>在 ”订阅转换模板” 的下拉栏中找到并选择 ”ACL4SSR 规则 Mini NoAuto” 。</li><li>以下配置请参考表格：</li></ol><table tabindex="0"><thead><tr><th>配置项</th><th>添加Emoji</th><th>UDP 支持</th><th>跳过证书验证</th><th>排序</th><th>插入节点类型</th><th>使用规则集</th></tr></thead><tbody><tr><td>设置值</td><td>启用</td><td>启用</td><td>禁用</td><td>禁用</td><td>禁用</td><td>禁用</td></tr></tbody></table><ol start="9"><li>剩余部分如不懂请保持默认，最后在页面底部点击 ”保存配置” 按钮。</li><li>在跳转后的页面底部点击 ”更新订阅” 按钮，至此节点导入部分已结束 。</li></ol><h2 id="三、开启代理" tabindex="-1">三、开启代理 <a class="header-anchor" href="#三、开启代理" aria-label="Permalink to &quot;三、开启代理&quot;">​</a></h2><ol><li>在点击 ”更新订阅” 按钮后，系统会自动回到 ”OpenClash” 的设置页。</li><li>在 ”运行状态” 的分页中， ”主程序” 栏如果不出意外的话应该会显示绿色的 ”运行中” ，这代表程序运行状态正常。</li></ol><div class="tip custom-block"><p class="custom-block-title">提示：</p><p>如果在 ”运行状态” 的分页中， ”主程序” 一栏显示的不是绿色的 ”运行中” 则多为启动失败，请根据 ”运行日志” 分页中的日志记录自行排障。</p></div><div class="tip custom-block"><p class="custom-block-title">补充：</p><p>关于造成第三方客户端崩溃或无法上网的成因繁多，更多为用户的配置不当或设备环境存在问题所导致。因运维精力有限，客服不会对第三方客户端遭遇故障做任何解答，请自行排障。</p></div><ol start="3"><li>最后，您可以点击 ”运行状态” 分页中的 ”Dashboard 控制面板” 按钮，在弹出的页面里根据您设置的出站模式与规则，选择需要的节点即可。</li></ol><div class="tip custom-block"><p class="custom-block-title">🎉 节点推荐</p><ul><li>🚀 <a href="https://www.xn--9kqrm7t.com/#/register?code=JRtE5uIV" target="_blank" rel="noreferrer">优信云：IEPL/IPLC 高速专线，￥15.00/月</a><br></li><li>🚀 <a href="https://erwan6.net/auth/register?code=BoObCd" target="_blank" rel="noreferrer">尔湾云：最大峰值1000Mbps，全流媒体及ChatGPT解锁！最低12元/月</a><br></li><li>🚀 <a href="https://haibing822.tntvipaff.cc/#/register?code=GtjJVgml" target="_blank" rel="noreferrer">TNTCloud：新开机场，季付30，每月低至￥10.00/月</a><br></li><li><a href="https://cinb01.xxfaff.cc/#/register?inviteCode=80C209ADC772" target="_blank" rel="noreferrer">小旋风：IPLC专线高速稳定！8元/月起</a><br></li><li><a href="https://ca01.dgy01.cc/#/register?code=JSSN0WQ9" target="_blank" rel="noreferrer">大哥云：年付低至7元/月，4年稳定老牌机场</a><br></li><li><a href="https://fchb1188.fcvipaff.cc/register?aff=X1vZd2wf" target="_blank" rel="noreferrer">肥猫云：全专线中转隧道，高速大宽带不限设备数，低至6元/月（年付）</a><br></li><li><a href="https://homes.tr25.cn?code=ReCm" target="_blank" rel="noreferrer">疾风云：包年 6.9折 优惠码: jf2025</a></li></ul></div>',20)]))}const f=e(o,[["render",i]]);export{m as __pageData,f as default};
